// ---------------------------------------------------------------------------
// Pre-filled model strings
// ---------------------------------------------------------------------------

/**
 * Simple linear regression with a continuous predictor x.
 * Parameters: alpha (intercept), beta (slope), sigma (residual SD).
 */
export const defaultModel1 = `model {
  for (i in 1:N) {
    y[i] ~ dnorm(mu[i], sigma)
    mu[i] <- alpha + beta * x[i]
  }
  alpha ~ dnorm(0, 5)
  beta ~ dnorm(0, 5)
  sigma ~ dunif(0, 100)
}`;

/**
 * Mixed-effects linear model with group-level random intercepts b[j].
 * Parameters: alpha, beta, sigma (residual SD), sigma.b (group SD).
 * Requires constants N (number of observations) and J (number of groups).
 */
export const defaultModel2 = `model {
  for (i in 1:N) {
    y[i] ~ dnorm(mu[i], sigma)
    mu[i] <- alpha + beta * x[i] + b[group[i]]
  }
  for (j in 1:J) {
    b[j] ~ dnorm(0, sigma.b)
  }
  alpha ~ dnorm(0, 5)
  beta ~ dnorm(0, 5)
  sigma ~ dunif(0, 100)
  sigma.b ~ dunif(0, 100)
}`;

/**
 * Poisson log-linear GLM using the unified default dataset.
 * y_count[i] ~ Poisson(lambda[i]),  log(lambda[i]) = alpha + beta * x[i]
 * True DGP: alpha = 1.0, beta = 0.5
 * Parameters: alpha (log-scale intercept), beta (log-scale slope).
 */
export const defaultModel3 = `model {
  for (i in 1:N) {
    y_count[i] ~ dpois(lambda[i])
    log(lambda[i]) <- alpha + beta * x[i]
  }
  alpha ~ dnorm(0, 5)
  beta ~ dnorm(0, 5)
}`;

/**
 * Bernoulli logistic regression GLM using the unified default dataset.
 * y_bin[i] ~ Bernoulli(p[i]),  logit(p[i]) = alpha + beta * x[i]
 * True DGP: alpha = 0, beta = 1.5
 * Parameters: alpha (log-odds intercept), beta (log-odds ratio slope).
 */
export const defaultModel4 = `model {
  for (i in 1:N) {
    y_bin[i] ~ dbern(p[i])
    logit(p[i]) <- alpha + beta * x[i]
  }
  alpha ~ dnorm(0, 5)
  beta ~ dnorm(0, 5)
}`;

/**
 * Mixed-effects model with both random intercepts AND random slopes per group.
 * Each group j gets its own intercept b[j] and slope c[j].
 * Parameters: alpha, beta, sigma (residual SD), sigma.b (intercept SD), sigma.c (slope SD).
 * Requires constants N and J.
 */
export const defaultModel5 = `model {
  for (i in 1:N) {
    y[i] ~ dnorm(mu[i], sigma)
    mu[i] <- alpha + beta * x[i] + b[group[i]] + c[group[i]] * x[i]
  }
  for (j in 1:J) {
    b[j] ~ dnorm(0, sigma.b)
    c[j] ~ dnorm(0, sigma.c)
  }
  alpha ~ dnorm(0, 5)
  beta ~ dnorm(0, 5)
  sigma ~ dunif(0, 100)
  sigma.b ~ dunif(0, 100)
  sigma.c ~ dunif(0, 100)
}`;
